using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using MyApp.Services;
using System;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

// Setup policy in Program.cs or Startup.cs:
// services.AddAuthorization(options => { options.AddPolicy("UploadPolicy", policy => policy.RequireAuthenticatedUser()); });

namespace MyApp.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "UploadPolicy")]
    public class UploadController : ControllerBase
    {
        private static readonly string[] AllowedExtensions = { ".pdf" };
        private static readonly int MaxFileNameLength = 64;
        private static readonly long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

        private readonly IFileStorageService _fileStorageService;
        private readonly ILogger<UploadController> _logger;

        public UploadController(IFileStorageService fileStorageService, ILogger<UploadController> logger)
        {
            _fileStorageService = fileStorageService;
            _logger = logger;
        }

        [HttpPost]
        [Authorize(Policy = "UploadPolicy")]
        [RequestSizeLimit(MaxFileSizeBytes)]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadPdf()
        {
            try
            {
                if (!Request.HasFormContentType || !Request.Form.Files.Any())
                {
                    _logger.LogWarning("UploadPdf: No file found in request.");
                    return BadRequest(new { error = "No file uploaded." });
                }

                var file = Request.Form.Files[0];

                if (file == null || file.Length == 0)
                {
                    _logger.LogWarning("UploadPdf: Empty file.");
                    return BadRequest(new { error = "Uploaded file is empty." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    _logger.LogWarning("UploadPdf: File too large.");
                    return BadRequest(new { error = "File size exceeds the allowed limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    _logger.LogWarning("UploadPdf: Invalid file name.");
                    return BadRequest(new { error = "Invalid file name." });
                }

                var extension = Path.GetExtension(originalFileName).ToLowerInvariant();
                if (!AllowedExtensions.Contains(extension))
                {
                    _logger.LogWarning("UploadPdf: Forbidden extension: {Extension}", extension);
                    return BadRequest(new { error = "File type not allowed." });
                }

                if (!await FileSignatureValidator.IsValidPdfAsync(file))
                {
                    _logger.LogWarning("UploadPdf: Invalid PDF signature.");
                    return BadRequest(new { error = "Uploaded file is not a valid PDF." });
                }

                var safeFileName = FileNameGenerator.GenerateSafeFileName(extension);

                var filePath = await _fileStorageService.SavePdfAsync(file, safeFileName);

                await _fileStorageService.InitializePdfDownload(filePath);

                var filePathDto = new FilePathDto { FilePath = filePath };

                _logger.LogInformation("UploadPdf: File uploaded and saved as {FilePath}", filePath);

                return Ok(filePathDto);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "UploadPdf: Unexpected error.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

