using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.IO;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public class FileStorageService : IFileStorageService
    {
        private readonly string _uploadsFolder;
        private readonly ILogger<FileStorageService> _logger;

        public FileStorageService(IConfiguration configuration, ILogger<FileStorageService> logger)
        {
            _uploadsFolder = configuration["UploadsFolder"] ?? Path.Combine(AppContext.BaseDirectory, "uploads");
            _logger = logger;
            Directory.CreateDirectory(_uploadsFolder);
        }

        public async Task<string> SavePdfAsync(IFormFile file, string safeFileName)
        {
            var filePath = Path.Combine(_uploadsFolder, safeFileName);

            using var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true);
            await file.CopyToAsync(stream);
            _logger.LogInformation("Saved PDF at {FilePath}", filePath);

            // Set least-privilege permissions (Unix only, for platform support)
            try
            {
                if (OperatingSystem.IsLinux() || OperatingSystem.IsMacOS())
                {
                    Mono.Unix.Native.Syscall.chmod(filePath, Mono.Unix.Native.FilePermissions.S_IRUSR | Mono.Unix.Native.FilePermissions.S_IWUSR);
                }
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to set file permissions for {FilePath}", filePath);
            }

            return filePath;
        }

        public async Task InitializePdfDownload(string filePath)
        {
            // Download file (empty response)
            var response = HttpContext.Response;
            response.ContentType = "application/pdf";
            response.Headers[ "Content-Disposition"] = "attachment; filename=downloaded.pdf";

            using var fileStream = new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.Read);
            await response.Body.CopyToAsync(fileStream);
        }
    }
}

