using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.IO;
using System.Threading.Tasks;

namespace YourNamespace.Configuration
{
    // Policy setup: In Startup/Program.cs, add a policy named "ConfigurePolicy"
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "ConfigurePolicy")]
    public class ConfigurationController : ControllerBase
    {
        private readonly IConfigurationRoot _configuration;
        private readonly ILogger<ConfigurationController> _logger;
        private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase) { ".xml" };
        private const int MaxFileNameLength = 128;
        private const int MaxFileSizeBytes = 1024 * 1024; // 1 MB

        public ConfigurationController(IConfigurationRoot configuration, ILogger<ConfigurationController> logger)
        {
            _configuration = configuration;
            _logger = logger;
        }

        [HttpPost("upload")]
        [Authorize(Policy = "ConfigurePolicy")]
        [RequestSizeLimit(MaxFileSizeBytes)]
        public async Task<IActionResult> UploadConfigAsync([FromForm] Microsoft.AspNetCore.Http.IFormFile file)
        {
            try
            {
                if (file == null || file.Length == 0)
                {
                    _logger.LogWarning("No file uploaded or file is empty.");
                    return BadRequest(new { error = "No file uploaded or file is empty." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    _logger.LogWarning("File size exceeds allowed limit: {FileSize}", file.Length);
                    return BadRequest(new { error = "File size exceeds allowed limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    _logger.LogWarning("Invalid file name: {FileName}", originalFileName);
                    return BadRequest(new { error = "Invalid file name." });
                }

                var extension = Path.GetExtension(originalFileName);
                if (!AllowedExtensions.Contains(extension))
                {
                    _logger.LogWarning("Disallowed file extension: {Extension}", extension);
                    return BadRequest(new { error = "File type not allowed." });
                }

                // Validate file signature for XML (first 4 bytes: <?xml)
                using (var stream = file.OpenReadStream())
                {
                    if (!await FileSignatureHelper.IsXmlFileAsync(stream))
                    {
                        _logger.LogWarning("File signature does not match XML signature.");
                        return BadRequest(new { error = "File content does not match expected XML format." });
                    }
                }

                // Define upload/storage location outside web root
                var uploadPath = Path.Combine(AppContext.BaseDirectory, "SafeUploads");
                Directory.CreateDirectory(uploadPath);

                var safeFileName = Guid.NewGuid().ToString("N") + extension;
                var fullPath = Path.Combine(uploadPath, safeFileName);

                // Save file with least-privilege permissions
                using (var fs = new FileStream(fullPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, FileOptions.None))
                {
                    await file.CopyToAsync(fs);
                }

                // Parse and store the XML in memory for safe reference only
                using (var fs = File.OpenRead(fullPath))
                {
                    var xmlString = await StreamReader.ReadToEndAsync(fs);
                    _configuration["CustomConfig"] = xmlString;
                }

                _logger.LogInformation("User {User} uploaded config file {SafeFileName}.", User?.Identity?.Name, safeFileName);
                return Ok(new { fileName = safeFileName });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error uploading configuration file.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

// Helpers/FileSignatureHelper.cs
using System.IO;
using System.Text;
using System.Threading.Tasks;

namespace YourNamespace.Configuration
{
    public static class FileSignatureHelper
    {
        private static readonly byte[] XmlSignature = Encoding.UTF8.GetBytes("<?xml ");

        public static async Task<bool> IsXmlFileAsync(Stream stream)
        {
            stream.Seek(0, SeekOrigin.Begin);
            var buffer = new byte[XmlSignature.Length];
            var bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length);
            stream.Seek(0, SeekOrigin.Begin);
            if (bytesRead < XmlSignature.Length)
            {
                return false;
            }
            for (int i = 0; i < XmlSignature.Length; i++)
            {
                if (buffer[i] != XmlSignature[i])
                {
                    return false;
                }
            }
            return true;
        }
    }
}

