using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using MyApp.Services;
using System;
using System.IO;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    // Policy setup: In Startup/Program, add a policy named "UploadProfilePicturePolicy"
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "UploadProfilePicturePolicy")]
    public class ProfilePictureController : ControllerBase
    {
        private readonly IProfilePictureStorageService _storageService;
        private readonly ILogger<ProfilePictureController> _logger;
        private readonly IConfiguration _configuration;

        public ProfilePictureController(
            IProfilePictureStorageService storageService,
            ILogger<ProfilePictureController> logger,
            IConfiguration configuration)
        {
            _storageService = storageService;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Authorize(Policy = "UploadProfilePicturePolicy")]
        [RequestSizeLimit(5 * 1024 * 1024)] // 5MB max size
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadProfilePicture()
        {
            try
            {
                if (!Request.HasFormContentType || Request.Form.Files.Count == 0)
                {
                    _logger.LogWarning("UploadProfilePicture: No file provided.");
                    return BadRequest(new { error = "No file uploaded." });
                }

                var file = Request.Form.Files[0];

                var result = await _storageService.SaveProfilePictureAsync(file, User);
                if (!result.Success)
                {
                    _logger.LogWarning("UploadProfilePicture: File upload failed. Error: {Error}", result.ErrorMessage);
                    return BadRequest(new { error = result.ErrorMessage });
                }

                _logger.LogInformation("UploadProfilePicture: File uploaded successfully. ServerFileName: {ServerFileName}", result.ServerFileName);
                return Ok(new { fileName = result.ServerFileName });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "UploadProfilePicture: Unhandled exception during file upload.");
                return StatusCode(500, new { error = "An unexpected error occurred." });
            }
        }
    }
}

