using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public class ProfilePictureStorageService : IProfilePictureStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif"
        };

        private static readonly Dictionary<string, byte[][]> AllowedSignatures = new Dictionary<string, byte[][]>(StringComparer.OrdinalIgnoreCase)
        {
            { ".jpg",  new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png",  new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47 } } },
            { ".gif",  new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } } }
        };

        private readonly ILogger<ProfilePictureStorageService> _logger;
        private readonly string _storageRoot;
        private readonly long _maxFileSize;

        public ProfilePictureStorageService(ILogger<ProfilePictureStorageService> logger, IConfiguration configuration)
        {
            _logger = logger;
            _storageRoot = configuration["ProfilePictures:StoragePath"] ?? Path.Combine(AppContext.BaseDirectory, "ProfilePictures");
            _maxFileSize = configuration.GetValue<long>("ProfilePictures:MaxFileSize", 5 * 1024 * 1024); // 5MB default
            Directory.CreateDirectory(_storageRoot);
        }

        public async Task<ProfilePictureUploadResult> SaveProfilePictureAsync(IFormFile file, ClaimsPrincipal user)
        {
            if (file == null)
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "File is required." };
            }

            if (file.Length == 0)
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "File is empty." };
            }

            if (file.Length > _maxFileSize)
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "File size exceeds the maximum allowed." };
            }

            var originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "Invalid file name." };
            }

            var extension = Path.GetExtension(originalFileName);
            if (!AllowedExtensions.Contains(extension))
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "File type not allowed." };
            }

            if (!await IsValidFileSignatureAsync(file, extension))
            {
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "File content does not match its extension." };
            }

            var safeFileName = $"{Guid.NewGuid():N}{extension}";
            var serverFileName = safeFileName;
            var savePath = Path.Combine(_storageRoot, serverFileName);

            try
            {
                using (var stream = new FileStream(savePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
                {
                    await file.CopyToAsync(stream);
                }

                // Set least-privilege permissions (platform-specific, example for Unix)
                try
                {
                    if (OperatingSystem.IsLinux() || OperatingSystem.IsMacOS())
                    {
                        Mono.Unix.Native.Syscall.chmod(savePath, Mono.Unix.Native.FilePermissions.S_IRUSR | Mono.Unix.Native.FilePermissions.S_IWUSR);
                    }
                }
                catch (Exception ex)
                {
                    _logger.LogWarning(ex, "Failed to set file permissions for {File}", savePath);
                }

                return new ProfilePictureUploadResult
                {
                    Success = true,
                    ServerFileName = serverFileName
                };
            }
            catch (IOException ex)
            {
                _logger.LogWarning(ex, "Failed to save file.");
                if (File.Exists(savePath))
                {
                    try
                    {
                        File.Delete(savePath);
                    }
                }
                return new ProfilePictureUploadResult { Success = false, ErrorMessage = "Failed to save file." };
            }
        }

        private async Task<bool> IsValidFileSignatureAsync(IFormFile file, string extension)
        {
            if (!AllowedSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            var maxSignatureLength = signatures.Max(s => s.Length);
            var buffer = new byte[maxSignatureLength];

            using (var stream = file.OpenReadStream())
            {
                var read = await stream.ReadAsync(buffer, 0, buffer.Length);
                foreach (var sig in signatures)
                {
                    if (buffer.Take(sig.Length).SequenceEqual(sig))
                    {
                        return true;
                    }
                }
            }
            return false;
        }
    }
}

