using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

namespace YourApp.Services
{
    public class ProfilePhotoStorageService : IProfilePhotoStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp"
        };

        private readonly string _storageRoot;
        private readonly long _maxFileSizeBytes;
        private readonly ILogger<ProfilePhotoStorageService> _logger;

        private static readonly Regex SafeFileNameRegex = new Regex(@"^[a-zA-Z0-9_\-\.]+$", RegexOptions.Compiled);

        public ProfilePhotoStorageService(IConfiguration configuration, ILogger<ProfilePhotoStorageService> logger)
        {
            _storageRoot = configuration.GetValue<string>("ProfilePhotos:StorageRoot") ?? Path.Combine(AppContext.BaseDirectory, "App_Data", "ProfilePhotos");
            _maxFileSizeBytes = configuration.GetValue<long>("ProfilePhotos:MaxFileSizeBytes", 2 * 1024 * 1024); // 2MB default
            _logger = logger;
        }

        public async Task<ProfilePhotoStorageResult> SaveProfilePhotoAsync(IFormFile file, string userId)
        {
            if (file == null)
            {
                return ProfilePhotoStorageResult.Failure("No file provided.");
            }

            if (file.Length == 0)
            {
                return ProfilePhotoStorageResult.Failure("File is empty.");
            }

            if (file.Length > _maxFileSizeBytes)
            {
                return ProfilePhotoStorageResult.Failure("File exceeds maximum allowed size.");
            }

            var originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
            {
                return ProfilePhotoStorageResult.Failure("Invalid file name.");
            }

            var extension = Path.GetExtension(originalFileName);
            if (string.IsNullOrEmpty(extension) || !AllowedExtensions.Contains(extension))
            {
                return ProfilePhotoStorageResult.Failure("File type is not allowed.");
            }

            if (!SafeFileNameRegex.IsMatch(originalFileName))
            {
                return ProfilePhotoStorageResult.Failure("File name contains invalid characters.");
            }

            // Defensive: Check file signature
            if (!FileSignatureValidator.IsValidSignature(file, extension))
            {
                return ProfilePhotoStorageResult.Failure("File content does not match the expected image signature.");
            }

            // Defensive: Generate safe unique file name
            var safeFileName = GenerateSafeFileName(extension);

            var userDirectory = Path.Combine(_storageRoot, userId);
            Directory.CreateDirectory(userDirectory);

            var filePath = Path.Combine(userDirectory, safeFileName);

            // Defensive: Prevent path traversal
            var normalizedPath = Path.GetFullPath(filePath);
            if (!normalizedPath.StartsWith(Path.GetFullPath(userDirectory), StringComparison.OrdinalIgnoreCase))
            {
                return ProfilePhotoStorageResult.Failure("Invalid file path.");
            }

            // Store with least privilege
            using (var stream = new FileStream(normalizedPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
            {
                await file.CopyToAsync(stream);
            }

            // Defensive: Set file permissions (platform dependent, omitted for brevity)

            // Publicly accessible
            var publicUrl = $"/api/profilephoto/{Uri.EscapeDataString(userId)}/{Uri.EscapeDataString(safeFileName)}";

            _logger.LogInformation("Profile photo uploaded for user {UserId}: {FileName}", userId, safeFileName);

            return ProfilePhotoStorageResult.Success(publicUrl);
        }

        private string GenerateSafeFileName(string extension)
        {
            using (var rng = RandomNumberGenerator.Create())
            {
                var bytes = new byte[16];
                rng.GetBytes(bytes);
                return $"{BitConverter.ToString(bytes).Replace("-", "").ToLowerInvariant()}{extension}";
            }
        }
    }
}

// Services/FileSignatureValidator.cs

using Microsoft.AspNetCore.Http;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace YourApp.Services
{
    public static class FileSignatureValidator
    {
        private static readonly Dictionary<string, byte[][]> Signatures = new Dictionary<string, byte[][]>
        {
            // jpg/jpeg
            [".jpg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".jpeg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            // png
            [".png"] = new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } },
            // gif
            [".gif"] = new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } },
            // bmp
            [".bmp"] = new[] { new byte[] { 0x42, 0x4D } },
            // webp
            [".webp"] = new[] { new byte[] { 0x52, 0x49, 0x46, 0x46 } }
        };

        public static bool IsValidSignature(IFormFile file, string extension)
        {
            if (!Signatures.TryGetValue(extension, out var allowedSignatures))
            {
                return false;
            }

            using (var stream = file.OpenReadStream())
            {
                foreach (var sig in allowedSignatures)
                {
                    var buffer = new byte[sig.Length];
                    if (stream.Read(buffer, 0, buffer.Length) != buffer.Length)
                    {
                        stream.Position = 0;
                        continue;
                    }
                    stream.Position = 0;
                    if (buffer.SequenceEqual(sig))
                    {
                        return true;
                    }
                }
            }
            return false;
        }
    }
}

