using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Buffers;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

// Policy setup required in Startup/Program:
// options.AddPolicy("UploadPolicy", policy => policy.RequireAuthenticatedUser());

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "UploadPolicy")]
    public class UploadController : ControllerBase
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".pdf"
        };

        private static readonly Dictionary<string, byte[]> FileSignatures = new Dictionary<string, byte[]>
        {
            { ".pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } } // %PDF
        };

        private const int MaxFileNameLength = 128;
        private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

        private readonly ILogger<UploadController> _logger;
        private readonly IConfiguration _configuration;
        private readonly IFileSignatureValidator _fileSignatureValidator;
        private readonly IFileStorageService _fileStorageService;

        public UploadController(
            ILogger<UploadController> logger,
            IConfiguration configuration,
            IFileSignatureValidator fileSignatureValidator,
            IFileStorageService fileStorageService)
        {
            _logger = logger;
            _configuration = configuration;
            _fileSignatureValidator = fileSignatureValidator;
            _fileStorageService = fileStorageService;
        }

        [HttpPost("upload")]
        [Authorize(Policy = "UploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFile()
        {
            try
            {
                if (!Request.HasFormContentType || Request.Form.Files.Count == 0)
                {
                    _logger.LogWarning("No file found in the upload request.");
                    return BadRequest(new { error = "No file uploaded." });
                }

                var file = Request.Form.Files[0];

                if (file == null || file.Length == 0)
                {
                    _logger.LogWarning("Uploaded file is empty.");
                    return BadRequest(new { error = "File is empty." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    _logger.LogWarning("Uploaded file exceeds allowed size. Size: {FileSize}", file.Length);
                    return BadRequest(new { error = $"File size exceeds {MaxFileSizeBytes / (1024 * 1024)} MB limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    _logger.LogWarning("Invalid file name: {FileName}", originalFileName);
                    return BadRequest(new { error = "Invalid file name." });
                }

                if (!IsSafeFileName(originalFileName))
                {
                    _logger.LogWarning("Unsafe file name: {FileName}", originalFileName);
                    return BadRequest(new { error = "Invalid file name." });
                }

                var fileExtension = Path.GetExtension(originalFileName);
                if (string.IsNullOrWhiteSpace(fileExtension) || !AllowedExtensions.Contains(fileExtension))
                {
                    _logger.LogWarning("Disallowed file extension: {Extension}", fileExtension);
                    return BadRequest(new { error = "PDF is the only allowed file type." });
                }

                // Validate file signature
                using (var memoryStream = new MemoryStream())
                {
                    await file.CopyToAsync(memoryStream);
                    memoryStream.Position = 0;

                    if (!_fileSignatureValidator.IsValidSignature(memoryStream, fileExtension))
                    {
                        _logger.LogWarning("File signature does not match extension for {FileName}", originalFileName);
                        return BadRequest(new { error = "File content does not match file type." });
                    }
                }

                // Generate safe server-side file name
                var safeFileName = GenerateSafeFileName(fileExtension);

                // Store outside web root
                var uploadFolder = _configuration["UploadSettings:UploadFolderPath"] ?? Path.Combine(AppContext.BaseDirectory, "SafeUploads");
                Directory.CreateDirectory(uploadFolder);

                var storeResult = await _fileStorageService.SaveFileAsync(file, uploadFolder, safeFileName);

                if (!storeResult)
                {
                    _logger.LogError("Failed to save file to disk.");
                    return StatusCode(500, new { error = "File storage failed." });
                }

                _logger.LogInformation("File uploaded successfully: {SafeFileName}", safeFileName);
                return Ok(new { fileName = safeFileName });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during file upload.");
                return StatusCode(500, new { error = "Unexpected server error." });
            }
        }

        private static bool IsSafeFileName(string fileName)
        {
            // Only allow alphanumeric, dash, underscore, and dot
            return Regex.IsMatch(fileName, @"^[\w\-.]+$");
        }

        private static string GenerateSafeFileName(string extension)
        {
            // Use a random filename with no PII and .pdf extension
            var randomBytes = RandomNumberGenerator.GetBytes(16);
            return $"{BitConverter.ToString(randomBytes).Replace("-", "")}{extension}";
        }
    }
}

