// Services/FileSignatureValidator.cs
using System;
using System.Collections.Generic;
using System.IO;

namespace MyApp
{
    public class FileSignatureValidator : IFileSignatureValidator
    {
        private readonly Dictionary<string, byte[]> _fileSignatures;

        public FileSignatureValidator()
        {
            _fileSignatures = new Dictionary<string, byte[]>(StringComparer.OrdinalIgnoreCase)
            {
                { ".pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } } // %PDF
            };
        }

        public bool IsValidSignature(Stream fileStream, string fileExtension)
        {
            if (!_fileSignatures.TryGetValue(fileExtension, out var signature))
            {
                return false;
            }

            var buffer = new byte[signature.Length];
            fileStream.Position = 0;
            using (var stream = File.OpenRead(fileStream.Name))
            {
                stream.Read(buffer, 0, buffer.Length);
            }

            for (int i = 0; i < signature.Length; i++)
            {
                if (buffer[i] != signature[i])
                {
                    return false;
                }
            }
            return true;
        }
    }
}

