using Microsoft.AspNetCore.Http;
using System;
using System.Collections.Generic;
using System.IO;

namespace MyApp.Models
{
    public static class FileSignatureValidator
    {
        private static readonly Dictionary<string, List<byte[]>> ImageSignatures = new()
        {
            // JPEG
            [".jpg"] = new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".jpeg"] = new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } },
            // PNG
            [".png"] = new List<byte[]> { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } },
            // GIF
            [".gif"] = new List<byte[]> { new byte[] { 0x47, 0x49, 0x46, 0x38 } }
        };

        public static bool IsValidImage(IFormFile file, string extension)
        {
            if (!ImageSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            using var stream = file.OpenReadStream();
            foreach (var signature in signatures)
            {
                stream.Seek(0, SeekOrigin.Begin);
                var buffer = new byte[signature.Length];
                var read = stream.Read(buffer, 0, signature.Length);
                if (read == signature.Length && IsMatch(buffer, signature))
                {
                    return true;
                }
            }
            return false;
        }

        private static bool IsMatch(byte[] buffer, byte[] signature)
        {
            for (int i = 0; i < signature.Length; i++)
            {
                if (buffer[i] != signature[i])
                {
                    return false;
                }
            }
            return true;
        }
    }
}

