using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.Buffers;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text;
using System.Threading.Tasks;

// Policy setup (in Program.cs or Startup.cs):
// services.AddAuthorization(options => { options.AddPolicy("ImageUploadPolicy", policy => policy.RequireAuthenticatedUser()); });

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "ImageUploadPolicy")]
    public class ImageController : ControllerBase
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png"
        };

        private static readonly Dictionary<string, byte[][]> FileSignatures = new Dictionary<string, byte[][]>
        {
            { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } } }
        };

        private const int MaxFileSizeBytes = 5 * 1024 * 1024; // 5 MB
        private const int MaxFileNameLength = 100;
        private readonly ILogger<ImageController> _logger;
        private readonly IConfiguration _configuration;

        public ImageController(ILogger<ImageController> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("upload-image")]
        [Authorize(Policy = "ImageUploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadImage()
        {
            try
            {
                if (!Request.HasFormContentType || Request.Form.Files.Count == 0)
                {
                    _logger.LogWarning("UploadImage: Missing file");
                    return BadRequest(new { error = "No file uploaded" });
                }

                var file = Request.Form.Files[0];

                if (file.Length == 0)
                {
                    _logger.LogWarning("UploadImage: Empty file");
                    return BadRequest(new { error = "File is empty" });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    _logger.LogWarning("UploadImage: File too large");
                    return BadRequest(new { error = "File too large" });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    _logger.LogWarning("UploadImage: Invalid filename");
                    return BadRequest(new { error = "Invalid filename" });
                }

                var extension = Path.GetExtension(originalFileName);
                if (!AllowedExtensions.Contains(extension))
                {
                    _logger.LogWarning("UploadImage: Disallowed extension {Extension}", extension);
                    return BadRequest(new { error = "File type not allowed" });
                }

                // Read file signature
                byte[] signatureBuffer = new byte[8];
                using (var sigStream = file.OpenReadStream())
                {
                    int read = sigStream.Read(signatureBuffer, 0, signatureBuffer.Length);
                    if (!IsValidSignature(extension, signatureBuffer, read))
                    {
                        _logger.LogWarning("UploadImage: Invalid file signature for extension {Extension}", extension);
                        return BadRequest(new { error = "File content does not match extension" });
                    }
                }

                // Generate safe server-side filename
                var safeFileName = GenerateSafeFileName(extension);

                // Store files outside web root; path from configuration or safe default
                var uploadBasePath = _configuration.GetValue<string>("UploadBasePath") ?? Path.Combine(AppContext.BaseDirectory, "SafeUploads");
                Directory.CreateDirectory(uploadBasePath);

                var filePath = Path.Combine(uploadBasePath, safeFileName);

                // Save file securely
                using (var targetStream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
                {
                    await file.CopyToAsync(targetStream);
                }

                // Encode file to base64 for response
                using (var fileBytes = File.OpenRead(filePath))
                {
                    var base64 = await FileToBase64Async(fileBytes);
                    File.Delete(filePath);
                    return Ok(new { image = base64 });
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "UploadImage: Unexpected error");
                return StatusCode(500, new { error = "Internal server error" });
            }
        }

        private static bool IsValidSignature(string extension, byte[] buffer, int read)
        {
            if (!FileSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            foreach (var sig in signatures)
            {
                if (buffer.Take(sig.Length).SequenceEqual(sig))
                {
                    return true;
                }
            }

            // For JPEG/PNG, check for magic header presence, not signature
            if ((extension.Equals(".jpg", StringComparison.OrdinalIgnoreCase) || extension.Equals(".jpeg", StringComparison.OrdinalIgnoreCase)) &&
                (buffer[0] == 0xFF && buffer[1] == 0xD8))
            {
                return true;
            }

            if ((extension.Equals(".png", StringComparison.OrdinalIgnoreCase)) &&
                buffer[0] == 0x89 && buffer[1] == 0x50 && buffer[2] == 0x4E && buffer[3] == 0x47)
            {
                return true;
            }

            return false;
        }

        private static string GenerateSafeFileName(string extension)
        {
            var random = new byte[16];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(random);
            }
            return Convert.ToBase64String(random).Replace('+', '-').Replace('/', '_') + extension;
        }

        private static async Task<string> FileToBase64Async(FileStream fileStream)
        {
            byte[] buffer = new byte[81920];
            using (var ms = new MemoryStream())
            {
                int read;
                while ((read = await fileStream.ReadAsync(buffer, 0, buffer.Length)) > 0)
                {
                    ms.Write(buffer, 0, read);
                }
                return Convert.ToBase64String(ms.ToArray());
            }
        }
    }
}

