namespace MyApi.Controllers
{
    // Policy setup: services.AddAuthorization(options => options.AddPolicy("RequireAdmin", policy => policy.RequireRole("Admin")));
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "RequireAdmin")]
    public class MyApiController : ControllerBase
    {
        private readonly IXmlDocumentProcessor _xmlDocumentProcessor;
        private readonly ILogger<MyApiController> _logger;

        public MyApiController(IXmlDocumentProcessor xmlDocumentProcessor, ILogger<MyApiController> logger)
        {
            _xmlDocumentProcessor = xmlDocumentProcessor;
            _logger = logger;
        }

        [HttpPost]
        [Route("process-xml")]
        [Authorize(Policy = "RequireAdmin")]
        public async Task<IActionResult> ProcessXmlAsync([FromForm] XmlUploadRequestDto request)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    return BadRequest(new { error = "Invalid request.", details = ModelState });
                }

                _logger.LogInformation("Received XML upload request for user: {User}", User?.Identity?.Name);

                var result = await _xmlDocumentProcessor.ProcessXmlDocumentAsync(request.XmlFile);

                return Ok(result);
            }
            catch (XmlProcessingException ex)
            {
                _logger.LogWarning("XML processing failed: {Message}", ex.Message);
                return BadRequest(new { error = "Invalid XML format.", details = ex.Message });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unhandled error during XML processing.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

