// Services/XmlDocumentProcessor.cs
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApi.Models;
using System;
using System.Buffers;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

namespace MyApi.Services
{
    public class XmlDocumentProcessor : IXmlDocumentProcessor
    {
        private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase)
        {
            ".xml"
        };

        private static readonly Dictionary<string, byte[]> AllowedSignatures = new()
        {
            { ".xml", new byte[] { 0x3C, 0x3F, 0x78, 0x6D, 0x6C } } // XML header: "<?xml"
        };

        private const int MaxFileNameLength = 100;
        private const long MaxFileSize = 2 * 1024 * 1024; // 2 MB

        private readonly string _uploadPath;
        private readonly ILogger<XmlDocumentProcessor> _logger;

        public XmlDocumentProcessor(IConfiguration configuration, ILogger<XmlDocumentProcessor> logger)
        {
            _uploadPath = configuration["XmlUpload:UploadPath"] ?? Path.Combine(Path.GetTempPath(), "uploads");
            _logger = logger;
        }

        public async Task<ProcessingResult> ProcessXmlDocumentAsync(IFormFile xmlFile)
        {
            if (xmlFile == null || xmlFile.Length == 0)
            {
                throw new XmlProcessingException("No file uploaded.");
            }

            if (xmlFile.Length > MaxFileSize)
            {
                throw new XmlProcessingException("File size exceeds the allowed limit.");
            }

            var fileName = Path.GetFileName(xmlFile.FileName);
            if (string.IsNullOrWhiteSpace(fileName) || fileName.Length > MaxFileNameLength)
            {
                throw new XmlProcessingException("Invalid file name.");
            }

            if (!IsFileNameSafe(fileName))
            {
                throw new XmlProcessingException("Unsafe file name.");
            }

            var ext = Path.GetExtension(fileName);
            if (!AllowedExtensions.Contains(ext))
            {
                throw new XmlProcessingException("File extension not allowed.");
            }

            // Generate a random, safe server-side file name
            var safeFileName = $"{Guid.NewGuid():N}{ext}";
            safeFileName = safeFileName.StartsWith(".") ? $"{safeFileName}" : safeFileName;

            // Store files outside web root
            var uploadDir = System.IO.Path.GetFullPath(_uploadPath);
            if (!Directory.Exists(uploadDir))
            {
                Directory.CreateDirectory(uploadDir);
            }

            var filePath = Path.Combine(uploadDir, safeFileName);

            // Validate file signature
            using (var fileStream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096))
            {
                await ValidateFileSignatureAsync(xmlFile, ext, fileStream);
            }

            // Copy file to memory (for max security)
            using (var inputStream = new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.Read))
            using (var outputStream = new MemoryStream())
            {
                await inputStream.CopyToAsync(outputStream);
                outputStream.Position = 0;

                // Parse XML from memory
                var xml = XDocument.Load(new StreamReader(outputStream));

                // Process XML as needed
                var processingResult = new ProcessingResult
                {
                    XmlContent = xml.ToString()
                };

                return processingResult;
            }
        }

        private static bool IsFileNameSafe(string fileName)
        {
            // Allow only alphanumeric, dash, underscore, dot
            return Regex.IsMatch(fileName, @"^[a-zA-Z0-9_\-\.]+$");
        }

        private async Task ValidateFileSignatureAsync(IFormFile file, string ext, FileStream output)
        {
            if (!AllowedSignatures.TryGetValue(ext, out var expectedSig))
            {
                throw new XmlProcessingException("Unknown file signature.");
            }

            var buffer = ArrayPool<byte>.Shared.Rent(expectedSig.Length);
            try
            {
                using (var stream = file.OpenReadStream())
                {
                    int bytesRead = await stream.ReadAsync(buffer, 0, expectedSig.Length);
                    if (bytesRead < expectedSig.Length)
                    {
                        throw new XmlProcessingException("File is too short.");
                    }

                    output.Write(buffer, 0, expectedSig.Length);
                    if (!buffer.Take(expectedSig.Length).SequenceEqual(expectedSig))
                    {
                        throw new XmlProcessingException("File signature mismatch.");
                    }

                    // After signature, copy remaining bytes
                    await stream.CopyToAsync(output);
                    output.Position = 0;
                }
            }
            finally
            {
                ArrayPool<byte>.Shared.Return(buffer);
            }
        }
    }
}

