using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public class FileStorageService : IFileStorageService
    {
        private readonly ILogger<FileStorageService> _logger;
        private readonly IConfiguration _configuration;
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".pdf"
        };
        private const int MaxFileNameLength = 100;
        private const long MaxFileSizeBytes = 5 * 1024 * 1024; // 5 MB per file
        private static readonly string[] AllowedFolders = new[] { "uploads" };
        private static readonly string UploadRoot = "App_Data"; // Outside web root, default ASP.NET Core location

        public FileStorageService(ILogger<FileStorageService> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
        }

        public async Task<FileStorageResult> SaveFilesAsync(IEnumerable<IFormFile> files, string folder, ClaimsPrincipal user)
        {
            var result = new FileStorageResult();
            result.UploadedFiles = new List<string>();

            if (files == null || !files.Any())
            {
                result.ErrorMessage = "No files uploaded.";
                result.Success = false;
                return result;
            }

            // Validate folder
            if (!string.IsNullOrWhiteSpace(folder) && !AllowedFolders.Contains(folder))
            {
                result.ErrorMessage = "Invalid upload folder.";
                result.Success = false;
                return result;
            }

            try
            {
                Directory.CreateDirectory(GetSafeUploadRoot(folder));

                foreach (var file in files)
                {
                    if (file.Length == 0)
                    {
                        result.ErrorMessage = "Empty file uploaded.";
                        result.Success = false;
                        return result;
                    }

                    if (file.Length > MaxFileSizeBytes)
                    {
                        result.ErrorMessage = $"File size exceeds limit ({MaxFileSizeBytes / (1024 * 1024)} MB).";
                        result.Success = false;
                        return result;
                    }

                    var originalFileName = Path.GetFileName(file.FileName);
                    if (originalFileName.Length > MaxFileNameLength)
                    {
                        result.ErrorMessage = "File name too long.";
                        result.Success = false;
                        return result;
                    }

                    var extension = Path.GetExtension(originalFileName);
                    if (!AllowedExtensions.Contains(extension))
                    {
                        result.ErrorMessage = $"File type {extension} is not allowed.";
                        result.Success = false;
                        return result;
                    }

                    // Check file signature for PDF (magic bytes: %PDF-)
                    if (!IsValidPdf(file))
                    {
                        result.ErrorMessage = "File content does not match PDF format.";
                        result.Success = false;
                        return result;
                    }

                    var safeFileName = GenerateSafeFileName(extension);
                    var savePath = Path.Combine(GetSafeUploadRoot(folder), safeFileName);

                    // Save file
                    using (var stream = new FileStream(savePath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
                    {
                        await file.CopyToAsync(stream);
                    }

                    // Set restrictive permissions (Windows/Linux: application user responsible)
                    SetFilePermissions(savePath);

                    result.UploadedFiles.Add(safeFileName);
                }

                result.Success = true;
            }
            catch (IOException ex)
            {
                _logger.LogError(ex, "File IO error during upload.");
                result.ErrorMessage = "File upload failed due to IO error.";
                result.Success = false;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during file upload.");
                result.ErrorMessage = "Unexpected error occurred.";
                result.Success = false;
            }

            return result;
        }

        private string GetSafeUploadRoot(string folder)
        {
            // Default upload root or specified folder
            var root = string.IsNullOrWhiteSpace(folder) ? UploadRoot : Path.Combine(UploadRoot, folder);
            return root;
        }

        private string GenerateSafeFileName(string extension)
        {
            var guid = Guid.NewGuid().ToString("N");
            return $"{guid}{extension}";
        }

        private void SetFilePermissions(string filePath)
        {
            // No-op for non-Windows, optionally implemented if needed (platform-specific)
        }

        private bool IsValidPdf(IFormFile file)
        {
            if (file.Length < 5)
            {
                return false;
            }
            byte[] buffer = new byte[5];
            using (var stream = file.OpenReadStream())
            {
                stream.Read(buffer, 0, 5);
            }
            // PDF files start with "%PDF-"
            return buffer[0] == 0x25 && buffer[1] == 0x50 && buffer[2] == 0x44 && buffer[3] == 0x46 && buffer[4] == 0x2D;
        }
    }
}

