namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "FileUploadPolicy")]
    public class FileUploadController : ControllerBase
    {
        private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".txt"
        };

        private static readonly Dictionary<string, byte[]> FileSignatures = new()
        {
            { ".jpg", new byte[] { 0xFF, 0xD8, 0xFF } },
            { ".jpeg", new byte[] { 0xFF, 0xD8, 0xFF } },
            { ".png", new byte[] { 0x89, 0x50, 0x4E, 0x47 } },
            { ".gif", new byte[] { 0x47, 0x49, 0x46, 0x38 } },
            { ".pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } },
            { ".txt", new byte[] { } }
        };

        private const int MaxFileSizeBytes = 5 * 1024 * 1024; // 5 MB
        private const int MaxFileNameLength = 100;
        private static readonly Regex SafeFileNameRegex = new("^[a-zA-Z0-9._-]+$", RegexOptions.Compiled);

        private readonly ILogger<FileUploadController> _logger;
        private readonly IConfiguration _configuration;

        public FileUploadController(ILogger<FileUploadController> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("upload")]
        [Authorize(Policy = "FileUploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadAsync([FromForm] IFormFile file)
        {
            try
            {
                if (file == null || file.Length == 0)
                {
                    return BadRequest(new { error = "No file provided." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    return BadRequest(new { error = $"File size exceeds the {MaxFileSizeBytes / (1024 * 1024)}MB limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    return BadRequest(new { error = "Invalid file name length." });
                }

                if (!SafeFileNameRegex.IsMatch(originalFileName))
                {
                    return BadRequest(new { error = "File name contains invalid characters." });
                }

                var fileExtension = Path.GetExtension(originalFileName);
                if (string.IsNullOrWhiteSpace(fileExtension) || !AllowedExtensions.Contains(fileExtension))
                {
                    return BadRequest(new { error = $"File type '{fileExtension}' is not allowed." });
                }

                // Validate file signature
                if (!await FileSignatureIsValidAsync(file, fileExtension))
                {
                    return BadRequest(new { error = "File content does not match its extension." });
                }

                // Generate a safe, unique server-side filename
                var safeFileName = GenerateSafeFileName(fileExtension);

                // Store outside web root, path from config or default
                var uploadBasePath = _configuration.GetValue<string>("UploadSettings:BasePath") ??
                                     Path.Combine(AppContext.BaseDirectory, "App_Data", "Uploads");
                var uploadDirectory = Path.GetFullPath(uploadBasePath);

                if (!Directory.Exists(uploadDirectory))
                {
                    Directory.CreateDirectory(uploadDirectory);
                }

                var filePath = Path.Combine(uploadDirectory, safeFileName);

                // Ensure file path is within intended directory
                if !string.StartsWith(filePath, uploadDirectory, StringComparison.OrdinalIgnoreCase)
                {
                    return BadRequest(new { error = "Invalid file path." });
                }

                using (var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, true))
                {
                    await file.CopyToAsync(stream);
                }

                // Optionally: scan/quarantine file here

                // Store file info in DB (via a separate, safe repository method)
                var dbFile = new DbFile
                {
                    FileName = safeFileName,
                    FileExtension = fileExtension,
                    FileSize = file.Length,
                    UploadedAt = DateTime.UtcNow
                };
                await DbFileRepository.AddAsync(dbFile);

                _logger.LogInformation("File uploaded: {SafeFileName}, {FileExtension}, {FileSize}", safeFileName, fileExtension, file.Length);

                return Ok(new { message = "File uploaded successfully." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "File upload failed.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private async Task<bool> FileSignatureIsValidAsync(IFormFile file, string extension)
        {
            if (!FileSignatures.TryGetValue(extension, out var signature) || signature.Length == 0)
            {
                return true; // Allow txt/pdf/jpg/png/etc. without signature
            }

            var buffer = new byte[signature.Length];
            using (var stream = file.OpenReadStream())
            {
                var bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length);
                if (bytesRead < signature.Length)
                {
                    return false;
                }
            }

            for (var i = 0; i < signature.Length; i++)
            {
                if (buffer[i] != signature[i])
                {
                    return false;
                }
            }
            return true;
        }

        private string GenerateSafeFileName(string extension)
        {
            var randomBytes = RandomNumberGenerator.GetBytes(16);
            var safeBase = BitConverter.ToString(randomBytes).Replace("-", "");
            return $"{safeBase}{extension}";
        }
    }
}

