using System;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;

namespace MyApp.Services
{
    public class FileUploadService : IFileUploadService
    {
        private static readonly string[] AllowedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".docx" };
        private static readonly int MaxFileNameLength = 100;
        private static readonly long MaxFileSizeBytes = 5 * 1024 * 1024; // 5 MB

        private readonly string _uploadRootPath;
        private readonly ILogger<FileUploadService> _logger;

        public FileUploadService(IConfiguration configuration, ILogger<FileUploadService> logger)
        {
            _uploadRootPath = configuration["UploadSettings:RootPath"] ?? Path.Combine(AppContext.BaseDirectory, "uploads");
            _logger = logger;
        }

        public async Task<bool> UploadFileAsync(FileUploadRequestDto request)
        {
            if (request.File == null)
            {
                throw new FileUploadValidationException("File is required.");
            }

            if (request.File.Length == 0)
            {
                throw new FileUploadValidationException("File is empty.");
            }

            if (request.File.Length > MaxFileSizeBytes)
            {
                throw new FileUploadValidationException("File size exceeds the allowed limit.");
            }

            var originalFileName = Path.GetFileName(request.File.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
            {
                throw new FileUploadValidationException("Invalid file name.");
            }

            var ext = Path.GetExtension(originalFileName).ToLowerInvariant();
            if (!AllowedExtensions.Contains(ext))
            {
                throw new FileUploadValidationException("File extension not allowed.");
            }

            // Check file signature for known types
            if (!IsValidFileSignature(request.File, ext))
            {
                throw new FileUploadValidationException("File signature does not match the extension.");
            }

            var safeFileName = GenerateSafeFileName(ext);

            // Ensure upload directory exists
            Directory.CreateDirectory(_uploadRootPath);

            var filePath = Path.Combine(_uploadRootPath, safeFileName);

            // Prevent path traversal
            if (!filePath.StartsWith(_uploadRootPath, StringComparison.Ordinal))
            {
                throw new FileUploadValidationException("Invalid file path.");
            }

            using (var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
            {
                await request.File.CopyToAsync(stream);
            }

            _logger.LogInformation("File uploaded: {SafeFileName}", safeFileName);

            // Post-upload: scan/quarantine, or trigger content release if required

            return true;
        }

        private static string GenerateSafeFileName(string ext)
        {
            var random = new byte[16];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(random);
            }
            return $"{BitConverter.ToString(random).Replace("-", "").ToLowerInvariant()}{ext}";
        }

        private static bool IsValidFileSignature(IFormFile file, string ext)
        {
            // Only basic checks for demonstration; in production, use a library or more thorough checks
            file.Position = 0;
            byte[] buffer = new byte[8];
            int read = file.OpenReadStream().Read(buffer, 0, buffer.Length);

            if (ext == ".jpg" || ext == ".jpeg")
            {
                // JPEG: FF D8 FF
                return read > 3 && buffer[0] == 0xFF && buffer[1] == 0xD8 && buffer[2] == 0xFF;
            }
            if (ext == ".png")
            {
                // PNG: 89 50 4E 47 0D 0A 1A 0A
                return read > 7 &&
                    buffer[0] == 0x89 && buffer[1] == 0x50 && buffer[2] == 0x4E &&
                    buffer[3] == 0x47 && buffer[4] == 0x0D && buffer[5] == 0x0A &&
                    buffer[6] == 0x1A && buffer[7] == 0x0A;
            }
            if (ext == ".gif")
            {
                // GIF: 47 49 46 38
                return read > 3 && buffer[0] == 0x47 && buffer[1] == 0x49 && buffer[2] == 0x46 && buffer[3] == 0x38;
            }
            if (ext == ".pdf")
            {
                // PDF: 25 50 44 46
                return read > 3 && buffer[0] == 0x25 && buffer[1] == 0x50 && buffer[2] == 0x44 && buffer[3] == 0x46;
            }
            if (ext == ".docx")
            {
                // DOCX: ZIP file signature: 50 4B 03 04
                return read > 3 && buffer[0] == 0x50 && buffer[1] == 0x4B && buffer[2] == 0x03 && buffer[3] == 0x04;
            }
            return false;
        }
    }
}

