namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "UploadPolicy")]
    public class UploadController : ControllerBase
    {
        private static readonly string[] AllowedExtensions = { ".pdf" };
        private static readonly string[] AllowedContentTypes = { "application/pdf" };
        private const int MaxFileNameLength = 100;
        private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB
        private readonly string _uploadsRoot;
        private readonly ILogger<UploadController> _logger;

        public UploadController(IConfiguration configuration, ILogger<UploadController> logger)
        {
            _uploadsRoot = configuration.GetValue<string>("UploadSettings:RootPath") ?? "/var/myapp/uploads";
            _logger = logger;
        }

        [HttpPost]
        [Route("upload")]
        [Authorize(Policy = "UploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFile([FromForm] FileUploadRequestDto dto)
        {
            try
            {
                if (dto.File == null || dto.File.Length == 0)
                {
                    return BadRequest(new { error = "No file uploaded." });
                }

                if (dto.File.Length > MaxFileSizeBytes)
                {
                    return BadRequest(new { error = "File size exceeds limit." });
                }

                var originalFileName = Path.GetFileName(dto.File.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    return BadRequest(new { error = "Invalid file name." });
                }

                var fileExtension = Path.GetExtension(originalFileName).ToLowerInvariant();
                if (!AllowedExtensions.Contains(fileExtension))
                {
                    return BadRequest(new { error = "File type not allowed." });
                }

                if (!AllowedContentTypes.Contains(dto.File.ContentType))
                {
                    return BadRequest(new { error = "Invalid content type." });
                }

                if (!FileSignatureValidator.IsPdf(dto.File))
                {
                    return BadRequest(new { error = "File content does not match PDF format." });
                }

                var safeFileName = $"{Guid.NewGuid():N}{fileExtension}";
                var uploadDirectory = Path.GetFullPath(_uploadsRoot);
                Directory.CreateDirectory(uploadDirectory);

                var filePath = Path.Combine(uploadDirectory, safeFileName);

                using (var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
                {
                    await dto.File.CopyToAsync(stream);
                }

                _logger.LogInformation("File uploaded: {SafeFileName}, Size: {FileSize}", safeFileName, dto.File.Length);

                return Ok(new { fileName = safeFileName });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error during file upload.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

