using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyWebApp.Services
{
    public class ProfilePictureStorageService : IProfilePictureStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { ".jpg", ".jpeg", ".png" };
        private static readonly Dictionary<string, byte[][]> FileSignatures = new Dictionary<string, byte[][]>
        {
            { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } } }
        };
        private const int MaxFileSizeBytes = 2 * 1024 * 1024; // 2 MB
        private const int MaxFileNameLength = 100;
        private readonly string _pictureStoragePath;
        private readonly ILogger<ProfilePictureStorageService> _logger;

        public ProfilePictureStorageService(IConfiguration configuration, ILogger<ProfilePictureStorageService> logger)
        {
            _pictureStoragePath = configuration.GetValue<string>("ProfilePictures:StoragePath") ?? Path.Combine(AppContext.BaseDirectory, "App_Data", "ProfilePictures");
            _logger = logger;
        }

        public async Task<ProfilePictureUploadResult> SaveProfilePictureAsync(IFormFile file, string uploadedBy)
        {
            if (file == null)
            {
                return ProfilePictureUploadResult.Fail("File is required.");
            }

            if (file.Length == 0)
            {
                return ProfilePictureUploadResult.Fail("File is empty.");
            }

            if (file.Length > MaxFileSizeBytes)
            {
                return ProfilePictureUploadResult.Fail("File size exceeds the maximum allowed size.");
            }

            var originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
            {
                return ProfilePictureUploadResult.Fail("Invalid file name.");
            }

            if (!Regex.IsMatch(originalFileName, @"^[\w\-. ]+$"))
            {
                return ProfilePictureUploadResult.Fail("File name contains invalid characters.");
            }

            var extension = Path.GetExtension(originalFileName);
            if (!AllowedExtensions.Contains(extension))
            {
                return ProfilePictureUploadResult.Fail("File type is not allowed.");
            }

            // Verify file signature (magic numbers)
            if (!await IsValidFileSignatureAsync(file, extension))
            {
                return ProfilePictureUploadResult.Fail("File content does not match its extension.");
            }

            // Generate a safe random file name to prevent collisions and path traversal
            var safeFileName = GenerateSafeFileName(extension);

            var safeUploadedBy = Path.GetFileName(uploadedBy ?? string.Empty) ?? "unknown";

            var targetPath = Path.Combine(_pictureStoragePath, safeFileName);

            // Ensure directory exists
            Directory.CreateDirectory(_pictureStoragePath);

            // Prevent overwrite
            if (System.IO.File.Exists(targetPath))
            {
                return ProfilePictureUploadResult.Fail("A profile picture has already been uploaded.");
            }

            try
            {
                using (var stream = new FileStream(targetPath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
                {
                    await file.CopyToAsync(stream);
                }

                // Set file permissions (least privilege)
                SetFilePermissions(targetPath);

                // Log successful upload (log file content/MD5/metadata)
                _logger.LogInformation("Profile picture uploaded by {User}. File: {FileName}", safeUploadedBy, safeFileName);

                return ProfilePictureUploadResult.Success(safeFileName);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to save profile picture.");
                return ProfilePictureUploadResult.Fail("Failed to save file.");
            }
        }

        private static string GenerateSafeFileName(string extension)
        {
            var random = Convert.ToBase64String(RandomNumberGenerator.GetBytes(12));
            return $"{DateTime.UtcNow:yyyyMMddHHmmssfff}_{random}{extension.ToLowerInvariant()}";
        }

        private static void SetFilePermissions(string filePath)
        {
            // For Windows, files are by default not executable.
            // For Linux, default permission is safe, but could be tuned if needed.
            // (No execution required for images)
        }

        private static async Task<bool> IsValidFileSignatureAsync(IFormFile file, string extension)
        {
            if (!FileSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            var maxSignatureLength = signatures.Max(s => s.Length);
            var buffer = new byte[maxSignatureLength];

            using (var stream = file.OpenReadStream())
            {
                var bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length);
                foreach (var signature in signatures)
                {
                    if (bytesRead >= signature.Length && buffer.Take(signature.Length).SequenceEqual(signature))
                    {
                        return true;
                    }
                }
            }

            return false;
        }
    }
}

