        [HttpPost("upload")]
        [Authorize(Policy = "UserSignup")]
        [RequestSizeLimit(MaxFileSizeBytes)]
        public async Task<IActionResult> UploadFile([FromForm] FileUploadDto uploadDto)
        {
            try
            {
                if (uploadDto.File == null || uploadDto.File.Length == 0)
                {
