                }

                var extension = Path.GetExtension(originalFileName);
                if (!AllowedExtensions.Contains(extension))
                {
                    return BadRequest(new { error = "File type not allowed." });
                }

                // Generate a safe random filename, strip dangerous chars
                var safeFileName = GenerateSafeFileName(extension);

                // Save file to disk (never overwrite existing, never store in web root)
                var uploadRoot = _configuration.GetValue<string>("FileUpload:UploadRoot") ?? "Uploads";
                var normalizedRoot = Path.GetFullPath(uploadRoot);
                Directory.CreateDirectory(normalizedRoot);

                var filePath = Path.Combine(normalizedRoot, safeFileName);

                using (var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
                {
                    await uploadDto.File.CopyToAsync(stream);
                }

                // Verify file signature/magic number for allowed types
                if (!FileSignatureValidator.IsValidSignature(filePath, extension))
                {
                    System.IO.File.Delete(filePath);
                    return BadRequest(new { error = "File content does not match extension." });
                }

                // Save file reference in database (not path, just identifier)
                var storedFileReference = await _fileStorageService.SaveFileAsync(new StoredFileDto
                {
                    OriginalFileName = originalFileName,
                    StoredFileName = safeFileName,
                    FileStoragePath = normalizedRoot
                });

                _logger.LogInformation("User {UserId} uploaded file {FileName} as {StoredFileName}", User?.Id, originalFileName, safeFileName);

                return Ok(new { fileId = storedFileReference.Id });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "File upload failed for user {UserId}", User?.Id);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static string GenerateSafeFileName(string extension)
        {
            var random = RandomNumberGenerator.GetBytes(16);
            var safe = BitConverter.ToString(random).Replace("-", "").ToLowerInvariant();
            return $"{safe}{extension}";
        }
    }
}

