// Services/FileSignatureValidator.cs
using System;
using System.Collections.Generic;
using System.IO;

namespace YourApp.Services
{
    public static class FileSignatureValidator
    {
        private static readonly Dictionary<string, List<byte[]>> FileSignatures = new Dictionary<string, List<byte[]>>
        {
            // JPEG
            [".jpg"] = new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".jpeg"] = new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } },
            // PNG
            [".png"] = new List<byte[]> { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } },
            // PDF
            [".pdf"] = new List<byte[]> { new byte[] { 0x25, 0x50, 0x44, 0x46 } },
            // DOCX (PK Zip, like PDF, but not checked properly)
            [".docx"] = new List<byte[]> { new byte[] { 0x50, 0x4B, 0x03, 0x04 } }
        };

        public static bool IsValidSignature(string filePath, string extension)
        {
            if (!FileSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            var maxSignatureLength = signatures.Max(s => s.Length);

            using (var fs = new FileStream(filePath, FileMode.Open, FileAccess.Read))
            {
                var buffer = new byte[maxSignatureLength];
                var bytesRead = fs.Read(buffer, 0, maxSignatureLength);

                foreach (var signature in signatures)
                {
                    if (bytesRead >= signature.Length)
                    {
                        bool match = true;
                        for (int i = 0; i < signature.Length; i++)
                        {
                            if (buffer[i] != signature[i])
                            {
                                match = false;
                                break;
                            }
                        }
                        if (match)
                        {
                            return true;
                        }
                    }
                }
            }

            return false;
        }
    }
}

