// Policy setup: In Startup/Program, add a policy named "XmlConfigUpload" to require administrative permissions.

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "XmlConfigUpload")]
    public class XmlConfigController : ControllerBase
    {
        private readonly ILogger<XmlConfigController> _logger;
        private readonly IConfiguration _configuration;
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { ".xml" };
        private static readonly Dictionary<string, byte[]> AllowedSignatures = new Dictionary<string, byte[]>
        {
            { ".xml", new byte[] { 0x3C, 0x3F, 0x78, 0x6D, 0x6C } } // XML: "<?xml"
        };
        private const int MaxFileSizeBytes = 1024 * 1024; // 1 MB
        private static readonly string UploadDirectory = "App_Data/XmlConfigs";

        public XmlConfigController(ILogger<XmlConfigController> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("upload")]
        [Authorize(Policy = "XmlConfigUpload")]
        [ValidateAntiForgeryToken]
        public IActionResult UploadXmlConfig([FromForm] XmlConfigUploadRequest request)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    return BadRequest(new { error = "Invalid file upload request." });
                }

                var file = request.File;
                if (file == null || file.Length == 0)
                {
                    return BadRequest(new { error = "No file provided." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    return BadRequest(new { error = "File size exceeds the allowed limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
                {
                    return BadRequest(new { error = "Invalid filename." });
                }

                var extension = Path.GetExtension(originalFileName);
                if (!AllowedExtensions.Contains(extension))
                {
                    return BadRequest(new { error = "File type not allowed." });
                }

                // Check file signature for XML (starts with "<?xml")
                if (!IsValidXmlSignature(file))
                {
                    return BadRequest(new { error = "File content is not a valid XML document." });
                }

                // Generate a safe server-side filename
                var safeFileName = $"{Guid.NewGuid():N}{extension}";

                // Store outside web root (appsettings should define the directory)
                var uploadRoot = _configuration.GetValue<string>("XmlConfigUpload:UploadDirectory", UploadDirectory);
                Directory.CreateDirectory(uploadRoot);

                var savePath = Path.Combine(uploadRoot, safeFileName);

                // Save file with limited permissions
                using (var fs = new FileStream(savePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, FileOptions.None))
                {
                    file.CopyTo(fs);
                }

                _logger.LogInformation("XML config file uploaded successfully. Safe filename: {SafeFileName}", safeFileName);

                return Ok(new { message = "Upload successful." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error uploading XML config.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private bool IsValidXmlSignature(Microsoft.AspNetCore.Http.IFormFile file)
        {
            if (file.Length < 5)
            {
                return false;
            }
            byte[] buffer = new byte[5];
            file.OpenReadStream().Read(buffer, 0, 5);

            foreach (var sig in AllowedSignatures.Values)
            {
                if (buffer.Take(sig.Length).SequenceEqual(sig))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

