namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "FileUploadPolicy")]
    public class FileUploadController : ControllerBase
    {
        private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif", ".pdf"
        };

        private static readonly Dictionary<string, byte[][]> FileSignatures = new()
        {
            [".jpg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".jpeg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".png"] = new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47 } },
            [".gif"] = new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } },
            [".pdf"] = new[] { new byte[] { 0x25, 0x50, 0x44, 0x46 } }
        };

        private const int MaxFileNameLength = 100;
        private const int MaxFileSizeBytes = 5 * 1024 * 1024; // 5 MB
        private static readonly Regex FileNameRegex = new("^[a-zA-Z0-9_\\-\\.]+$");

        private readonly ILogger<FileUploadController> _logger;
        private readonly IConfiguration _configuration;

        public FileUploadController(ILogger<FileUploadController> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("Upload")]
        [Authorize(Policy = "FileUploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFiles()
        {
            try
            {
                var files = Request.Form.Files;
                if (files == null || files.Count == 0)
                {
                    return BadRequest(new { error = "No files were uploaded." });
                }

                var baseUploadPath = _configuration.GetValue<string>("FileUpload:BasePath", Path.Combine(Path.GetTempPath(), "uploads"));
                Directory.CreateDirectory(baseUploadPath);

                var uploadedFiles = new List<UploadedFile>();

                foreach (var file in files)
                {
                    var result = await ProcessSingleFile(file, baseUploadPath);
                    uploadedFiles.Add(result);
                }

                _logger.LogInformation("Files uploaded: {Count}", uploadedFiles.Count);
                return Ok(uploadedFiles);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "File upload failed");
                return StatusCode(500, new { error = "File upload failed due to a server error." });
            }
        }

        private async Task<UploadedFile> ProcessSingleFile(IFormFile file, string baseUploadPath)
        {
            if (file == null)
            {
                throw new ArgumentNullException(nameof(file));
            }

            if (file.Length == 0)
            {
                throw new ArgumentException("Empty file.");
            }

            if (file.Length > MaxFileSizeBytes)
            {
                throw new ArgumentException("File too large.");
            }

            var originalFileName = Path.GetFileName(file.FileName);

            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
            {
                throw new ArgumentException("Invalid file name.");
            }

            if (!FileNameRegex.IsMatch(originalFileName))
            {
                throw new ArgumentException("File name contains invalid characters.");
            }

            var extension = Path.GetExtension(originalFileName);
            if (string.IsNullOrWhiteSpace(extension) || !AllowedExtensions.Contains(extension))
            {
                throw new ArgumentException("File type not allowed.");
            }

            // Verify file signature
            if (!await FileSignatureMatchesAsync(file, extension))
            {
                throw new ArgumentException("File signature does not match extension.");
            }

            // Generate a safe, unique server-side filename
            var safeFileName = GenerateSafeFileName(extension);

            var destinationPath = Path.Combine(baseUploadPath, safeFileName);

            // Save file outside web root, least privilege, no executable permissions
            using (var stream = new FileStream(destinationPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
            {
                await file.CopyToAsync(stream);
            }

            // Set restrictive permissions (platform-specific, e.g., on Unix)
            SetRestrictivePermissions(destinationPath);

            var uploadedFile = new UploadedFile
            {
                OriginalFileName = originalFileName,
                UploadedFileName = safeFileName,
                Length = file.Length
            };

            return uploadedFile;
        }

        private async Task<bool> FileSignatureMatchesAsync(IFormFile file, string extension)
        {
            if (!FileSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            var maxSignatureLength = signatures.Max(s => s.Length);
            var buffer = ArrayPool<byte>.Shared.Rent(maxSignatureLength);

            try
            {
                using (var stream = file.OpenReadStream())
                {
                    var read = await stream.ReadAsync(buffer.AsMemory(0, maxSignatureLength));
                    foreach (var sig in signatures)
                    {
                        if (read >= sig.Length && buffer.Take(sig.Length).SequenceEqual(sig))
                        {
                            return true;
                        }
                    }
                }
                return false;
            }
            finally
            {
                ArrayPool<byte>.Shared.Return(buffer);
            }
        }

        private string GenerateSafeFileName(string extension)
        {
            var random = RandomNumberGenerator.Create();
            var bytes = new byte[16];
            random.GetBytes(bytes);
            var hex = bytes.Select(b => b.ToString("X2", CultureInfo.InvariantCulture)).JoinToString();
            return $"{hex}{extension}";
        }

        private void SetRestrictivePermissions(string filePath)
        {
            // Implementation is platform-specific, e.g., on Unix: chmod 600
            // No-op for this sample, but placeholder for actual implementation.
        }
    }
}

