namespace MyApp.Controllers
{
    // Policy setup: services.AddAuthorization(options => options.AddPolicy("UploadPolicy", policy => policy.RequireAuthenticatedUser()));
    [Authorize(Policy = "UploadPolicy")]
    [ApiController]
    [Route("api/[controller]")]
    public class MyController : ControllerBase
    {
        private readonly ILogger<MyController> _logger;
        private readonly IDataRepository _dataRepository;
        private readonly IXmlParserService _xmlParserService;

        public MyController(ILogger<MyController> logger, IDataRepository dataRepository, IXmlParserService xmlParserService)
        {
            _logger = logger;
            _dataRepository = dataRepository;
            _xmlParserService = xmlParserService;
        }

        [Authorize(Policy = "UploadPolicy")]
        [HttpPost("upload")]
        [RequestSizeLimit(10 * 1024 * 1024)] // 10 MB limit
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadXml([FromForm] XmlUploadRequestDto request)
        {
            try
            {
                if (request.File == null || request.File.Length == 0)
                {
                    _logger.LogWarning("UploadXml: No file uploaded or file is empty.");
                    return BadRequest(new { error = "No file uploaded or file is empty." });
                }

                var safeFileName = _xmlParserService.GenerateSafeFileName(request.File.FileName);
                if (safeFileName == null)
                {
                    _logger.LogWarning("UploadXml: Invalid file name.");
                    return BadRequest(new { error = "Invalid file name." });
                }

                // Save the upload outside web root, for example: "uploads/temp/{GUID}.xml"
                var uploadTempDir = "uploads/temp";
                System.IO.Directory.CreateDirectory(uploadTempDir);

                var fullPath = System.IO.Path.Combine(uploadTempDir, Guid.NewGuid() + ".xml");

                using (var fileStream = new System.IO.FileStream(fullPath, System.IO.FileMode.CreateNew, System.IO.FileAccess.Write))
                {
                    await request.File.CopyToAsync(fileStream);
                }

                if (!_xmlParserService.IsFileSignatureValid(fullPath))
                {
                    System.IO.File.Delete(fullPath);
                    _logger.LogWarning("UploadXml: File signature invalid.");
                    return BadRequest(new { error = "File content does not match XML format." });
                }

                Data data;
                try
                {
                    data = _xmlParserService.ParseXmlFile(fullPath);
                }
                catch (Exception ex)
                {
                    System.IO.File.Delete(fullPath);
                    _logger.LogWarning("UploadXml: Parsing failed: {Message}", ex.Message);
                    return BadRequest(new { error = "Failed to parse XML file." });
                }

                System.IO.File.Delete(fullPath);

                _dataRepository.InsertData(data);

                _logger.LogInformation("UploadXml: XML file uploaded successfully.");
                return Ok(new { message = "Upload successful." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "UploadXml: Unhandled error during upload.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

