// Services/XmlParserService.cs
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.IO;
using System.Text;
using System.Xml;
using System.Linq;
using System.Security.Cryptography;

namespace MyApp.Services
{
    public class XmlParserService : IXmlParserService
    {
        private readonly ILogger<XmlParserService> _logger;

        public XmlParserService(ILogger<XmlParserService> logger)
        {
            _logger = logger;
        }

        public string GenerateSafeFileName(string originalFileName)
        {
            if (string.IsNullOrWhiteSpace(originalFileName))
            {
                return null;
            }
            // Only allow .xml extensions
            var name = Path.GetFileNameWithoutExtension(originalFileName);
            if (name.Length > 64)
            {
                name = name.Substring(0, 64);
            }
            if (!name.All(c => char.IsLetterOrDigit(c) || c == '-' || c == '_'))
            {
                return null;
            }
            return name + ".xml";
        }

        public bool IsFileSignatureValid(string filePath)
        {
            // XML files start with <?xml ...: skip first 100 bytes, check for '<'
            var buffer = new byte[100];
            try
            {
                using (var fs = new FileStream(filePath, FileMode.Open, FileAccess.Read))
                {
                    if (fs.Read(buffer, 0, buffer.Length) <= 0)
                    {
                        return false;
                    }
                }
                for (int i = 0; i < buffer.Length; i++)
                {
                    if (buffer[i] != 0x3C /* < */)
                    {
                        return false;
                    }
                }
                return true;
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Error reading file signature.");
                return false;
            }
        }

        public Data ParseXmlFile(string filePath)
        {
            var data = new Data();
            using (var fs = new FileStream(filePath, FileMode.Open, FileAccess.Read))
            {
                var xmlDoc = new XmlDocument();
                xmlDoc.Load(fs);

                var root = xmlDoc.DocumentElement;
                if (root == null)
                {
                    throw new Exception("XML does not have a root element.");
                }

                var field1 = root.GetElementsByTagName("Field1");
                if (field1.Count > 0 && field1[0].HasChildNodes && field1[0].FirstChild.NodeType == XmlNodeType.Text)
                {
                    data.Field1 = field1[0].FirstChild.Value.Trim();
                }

                var field2 = root.GetElementsByTagName("Field2");
                if (field2.Count > 0 && field2[0].HasChildNodes && field2[0].FirstChild.NodeType == XmlNodeType.Text)
                {
                    data.Field2 = field2[0].FirstChild.Value.Trim();
                }

                var field3 = root.GetElementsByTagName("Field3");
                if (field3.Count > 0 && field3[0].HasChildNodes && field3[0].FirstChild.NodeType == XmlNodeType.Text)
                {
                    data.Field3 = field3[0].FirstChild.Value.Trim();
                }
            }
            return data;
        }
    }
}

