using Microsoft.Extensions.Configuration;
using MyApp.Models;
using System.Data;
using System.Data.SqlClient;

namespace MyApp.Repositories
{
    public class DataRepository : IDataRepository
    {
        private readonly IConfiguration _configuration;

        public DataRepository(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public void InsertData(Data data)
        {
            var connectionString = _configuration["ConnectionStrings:DefaultConnection"];
            using (var connection = new SqlConnection(connectionString))
            {
                connection.Open();
                using (var command = new SqlCommand("InsertIntoData", connection))
                {
                    command.CommandType = CommandType.StoredProcedure;
                    command.Parameters.AddWithValue("@Field1", data.Field1 ?? DBNull.Value);
                    command.Parameters.AddWithValue("@Field2", data.Field2 ?? DBNull.Value);
                    command.Parameters.AddWithValue("@Field3", data.Field3 ?? DBNull.Value);
                    command.ExecuteNonQuery();
                }
            }
        }
    }
}

