using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public class ProfilePictureStorageService : IProfilePictureStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif"
        };

        private static readonly Dictionary<string, byte[][]> FileSignatures = new Dictionary<string, byte[][]>
        {
            [".jpg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".jpeg"] = new[] { new byte[] { 0xFF, 0xD8, 0xFF } },
            [".png"] = new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47 } },
            [".gif"] = new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } }
        };

        private readonly string _storageRoot;
        private readonly ILogger<ProfilePictureStorageService> _logger;

        public ProfilePictureStorageService(IConfiguration configuration, ILogger<ProfilePictureStorageService> logger)
        {
            _storageRoot = configuration.GetValue<string>("ProfilePictures:StoragePath") ?? Path.Combine(AppContext.BaseDirectory, "App_Data", "ProfilePictures");
            _logger = logger;
        }

        public async Task<ProfilePictureSaveResult> SaveProfilePictureAsync(IFormFile file)
        {
            if (file == null)
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File is required." };
            }

            if (file.Length == 0)
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File is empty." };
            }

            if (file.Length > 5 * 1024 * 1024)
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File exceeds maximum allowed size." };
            }

            var originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "Invalid file name." };
            }

            if (!IsSafeFileName(originalFileName))
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File name contains invalid characters." };
            }

            var ext = Path.GetExtension(originalFileName);
            if (string.IsNullOrWhiteSpace(ext) || !AllowedExtensions.Contains(ext))
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File type is not allowed." };
            }

            if (!await IsValidFileSignatureAsync(file, ext))
            {
                return new ProfilePictureSaveResult { Success = false, ErrorMessage = "File signature does not match the file type." };
            }

            var safeFileName = GenerateSafeFileName(ext);
            var storagePath = Path.Combine(_storageRoot, safeFileName);

            Directory.CreateDirectory(_storageRoot);

            using (var stream = new FileStream(storagePath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
            {
                await file.CopyToAsync(stream);
            }

            // Optionally: scan or quarantine the file here before making it available

            return new ProfilePictureSaveResult { Success = true, StoredFileName = safeFileName };
        }

        private static bool IsSafeFileName(string fileName)
        {
            // Only allow alphanumeric, dash, underscore, and single dot
            return Regex.IsMatch(fileName, @"^[a-zA-Z0-9_\-\.]+$") && !fileName.Contains("..");
        }

        private static string GenerateSafeFileName(string ext)
        {
            var random = Convert.ToBase64String(RandomNumberGenerator.GetBytes(16)).Replace('+', '-').Replace('/', '_');
            return $"{random}{ext}";
        }

        private static async Task<bool> IsValidFileSignatureAsync(IFormFile file, string ext)
        {
            if (!FileSignatures.TryGetValue(ext, out var signatures))
            {
                return false;
            }

            var maxSignatureLength = signatures.Max(s => s.Length);
            var buffer = new byte[maxSignatureLength];

            using (var stream = file.OpenReadStream())
            {
                var read = await stream.ReadAsync(buffer, 0, buffer.Length);
                foreach (var sig in signatures)
                {
                    if (buffer.Take(sig.Length).SequenceEqual(sig))
                    {
                        return true;
                    }
                }
            }
            return false;
        }
    }
}

