using System.Linq;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using System.Threading.Tasks;

namespace MyWebApp.Services
{
    public class ProfilePictureStorageService : IProfilePictureStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif"
        };

        private static readonly Dictionary<string, byte[][]> FileSignatures = new Dictionary<string, byte[][]>
        {
            { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47 } } },
            { ".gif", new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } } }
        };

        private readonly string _storageRoot;
        private readonly ILogger<ProfilePictureStorageService> _logger;
        private readonly long _maxFileSize;

        public ProfilePictureStorageService(IConfiguration configuration, IWebHostEnvironment env, ILogger<ProfilePictureStorageService> logger)
        {
            _logger = logger;
            _storageRoot = configuration["ProfilePictureStorage:RootPath"] ??
                           Path.Combine(env.ContentRootPath, "App_Data", "ProfilePictures");
            _maxFileSize = configuration.GetValue<long>("ProfilePictureStorage:MaxFileSize", 5 * 1024 * 1024); // 5 MB default
            Directory.CreateDirectory(_storageRoot);
        }

        public async Task<ProfilePictureSaveResult> SaveProfilePictureAsync(IFormFile file)
        {
            if (file == null)
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "No file provided."
                };
            }

            if (file.Length == 0)
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "File is empty."
                };
            }

            if (file.Length > _maxFileSize)
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "File exceeds maximum allowed size."
                };
            }

            var originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "Invalid file name."
                };
            }

            if (!Regex.IsMatch(originalFileName, @"^[\w\-. ]+$"))
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "File name contains invalid characters."
                };
            }

            var extension = Path.GetExtension(originalFileName);
            if (string.IsNullOrWhiteSpace(extension) || !AllowedExtensions.Contains(extension))
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "File type not allowed."
                };
            }

            // Check file signature
            if (!await IsValidFileSignatureAsync(file, extension))
            {
                return new ProfilePictureSaveResult
                {
                    Success = false,
                    ErrorMessage = "File signature does not match extension."
                };
            }

            // Generate a safe random filename to avoid collisions and path traversal
            var safeFileName = GenerateSafeFileName(extension);

            var fullPath = Path.Combine(_storageRoot, safeFileName);

            using (var stream = new FileStream(fullPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
            {
                await file.CopyToAsync(stream);
            }

            // Set least-privilege permissions (platform-specific, omitted for brevity)

            // Optionally: scan/quarantine file here before making it available

            return new ProfilePictureSaveResult
            {
                Success = true,
                StoredFileName = safeFileName
            };
        }

        private static string GenerateSafeFileName(string extension)
        {
            using (var rng = RandomNumberGenerator.Create())
            {
                var bytes = new byte[16];
                rng.GetBytes(bytes);
                return $"{BitConverter.ToString(bytes).Replace("-", "").ToLowerInvariant()}{extension}";
            }
        }

        private static async Task<bool> IsValidFileSignatureAsync(IFormFile file, string extension)
        {
            if (!FileSignatures.TryGetValue(extension, out var signatures))
            {
                return false;
            }

            file.Position = 0;
            var maxSignatureLength = signatures.Max(s => s.Length);
            var buffer = new byte[maxSignatureLength];

            using (var stream = file.OpenReadStream())
            {
                var read = await stream.ReadAsync(buffer, 0, buffer.Length);
                foreach (var signature in signatures)
                {
                    if (buffer.Take(signature.Length).SequenceEqual(signature))
                    {
                        return true;
                    }
                }
            }

            return false;
        }
    }
}

