using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

// Policy setup (in Program.cs or Startup.cs):
// services.AddAuthorization(options => { options.AddPolicy("UploadPolicy", policy => policy.RequireAuthenticatedUser()); });

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "UploadPolicy")]
    public class UploadController : ControllerBase
    {
        private readonly ILogger<UploadController> _logger;
        private readonly string _uploadsFolder;
        private readonly IConfiguration _configuration;
        private static readonly string[] AllowedExtensions = { ".pdf" };
        private static readonly string[] AllowedContentTypes = { "application/pdf" };
        private const int MaxFileNameLength = 100;
        private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

        public UploadController(ILogger<UploadController> logger, IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
            _uploadsFolder = _configuration.GetValue<string>("UploadsFolder", Path.Combine(AppContext.BaseDirectory, "uploads"));
            Directory.CreateDirectory(_uploadsFolder);
        }

        [HttpPost]
        [Route("upload")]
        [Authorize(Policy = "UploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFile()
        {
            try
            {
                if (!Request.HasFormContentType || Request.Form.Files.Count == 0)
                {
                    return BadRequest(new { error = "No file uploaded." });
                }

                var file = Request.Form.Files[0];

                if (file == null || file.Length == 0)
                {
                    return BadRequest(new { error = "Empty file." });
                }

                if (file.Length > MaxFileSizeBytes)
                {
                    return BadRequest(new { error = "File too large." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > MaxFileNameLength)
                {
                    return BadRequest(new { error = "Invalid filename length." });
                }

                // Normalize filename and remove any path traversal attempts
                var safeFileName = FileNameSanitizer.GenerateSafeFileName(originalFileName, AllowedExtensions);

                // Validate file signature (magic number) for PDF files
                if (!await FileSignatureValidator.IsPdfAsync(file))
                {
                    return BadRequest(new { error = "File content does not match PDF format." });
                }

                // Generate unique server-side filename to prevent overwrite
                string uniqueFileName = $"{Guid.NewGuid():N}{AllowedExtensions}";
                string destinationPath = Path.Combine(_uploadsFolder, uniqueFileName);

                // Store file outside web root
                using (var fileStream = new FileStream(destinationPath, FileMode.CreateNew, FileAccess.Write, FileShare.None))
                {
                    await file.CopyToAsync(fileStream);
                }

                _logger.LogInformation("File uploaded: {SafeFileName}, Size: {FileSize}", safeFileName, file.Length);

                return Ok(new { message = "File uploaded successfully." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error during file upload.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

// Helpers/FileNameSanitizer.cs
using System;
using System.IO;
using System.Linq;
using System.Text.RegularExpressions;

namespace MyApp.Helpers
{
    public static class FileNameSanitizer
    {
        private static readonly Regex InvalidCharsRegex = new Regex(@"[^a-zA-Z0-9_\-\.]", RegexOptions.Compiled);

        public static string GenerateSafeFileName(string originalFileName, string[] allowedExtensions)
        {
            string baseName = Path.GetFileNameWithoutExtension(originalFileName);
            string extension = Path.GetExtension(originalFileName).ToLowerInvariant();

            if (!allowedExtensions.Contains(extension))
            {
                throw new ArgumentException("Extension not allowed.");
            }

            baseName = InvalidCharsRegex.Replace(baseName, "_");
            if (string.IsNullOrWhiteSpace(baseName) || baseName.Length > 100)
            {
                baseName = Path.GetFileNameWithoutExtension(originalFileName);
                baseName = baseName.Length > 100 ? baseName.Substring(0, 100) : baseName;
                baseName = InvalidCharsRegex.Replace(baseName, "_");
            }

            return $"{baseName}{extension}";
        }
    }
}

// Helpers/FileSignatureValidator.cs
using System;
using System.IO;
using System.Threading.Tasks;

namespace MyApp.Helpers
{
    public static class FileSignatureValidator
    {
        // PDF files start with "%PDF"
        private static readonly byte[] PdfMagic = new byte[] { 0x25, 0x50, 0x44, 0x46 }; // %PDF

        public static async Task<bool> IsPdfAsync(Microsoft.AspNetCore.Http.IFormFile file)
        {
            if (file == null)
            {
                return false;
            }

            if (file.Length < PdfMagic.Length)
            {
                return false;
            }

            try
            {
                using (var stream = file.OpenReadStream())
                {
                    var buffer = new byte[PdfMagic.Length];
                    int read = await stream.ReadAsync(buffer, 0, PdfMagic.Length);
                    if (read != PdfMagic.Length)
                    {
                        return false;
                    }

                    for (int i = 0; i < PdfMagic.Length; i++)
                    {
                        if (buffer[i] != PdfMagic[i])
                        {
                            return false;
                        }
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }
    }
}

