// Repositories/DataRepository.cs
using MyApp.Models;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System.Data;
using System.Data.SqlClient;
using System.Threading.Tasks;

namespace MyApp.Repositories
{
    public class DataRepository : IDataRepository
    {
        private readonly ILogger<DataRepository> _logger;
        private readonly string _connectionString;

        public DataRepository(ILogger<DataRepository> logger, IConfiguration configuration)
        {
            _logger = logger;
            _connectionString = configuration.GetConnectionString("DefaultConnection");
        }

        public async Task InsertAsync(XmlModel xmlModel)
        {
            using (var connection = new SqlConnection(_connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand("sp_InsertXmlModel", connection))
                {
                    command.CommandType = CommandType.StoredProcedure;
                    command.Parameters.AddWithValue("@Id", xmlModel.Id);
                    command.Parameters.AddWithValue("@Name", xmlModel.Name);
                    command.Parameters.AddWithValue("@Description", xmlModel.Description);

                    await command.ExecuteNonQueryAsync();
                }
            }
        }
    }
}

// Utils/XmlModelParser.cs
using Microsoft.AspNetCore.Http;
using System.IO;
using System.Threading.Tasks;
using System.Xml;
using System.Xml.Serialization;
using MyApp.Models;

namespace MyApp
{
    public static class XmlModelParser
    {
        public static async Task<XmlModel> ParseAsync(IFormFile file)
        {
            if (file == null)
            {
                throw new XmlParseException("File is required.");
            }

            if (file.Length == 0)
            {
                throw new XmlParseException("File is empty.");
            }

            if (file.Length > 2 * 1024 * 1024)
            {
                throw new XmlParseException("File size exceeds 2MB limit.");
            }

            var settings = new XmlReaderSettings
            {
                DtdProcessing = DtdProcessing.Prohibit,
                XmlResolver = null
            };

            XmlModel.XmlSerializer = new XmlSerializer(typeof(XmlModel));

            using (var stream = file.OpenReadStream())
            using (var reader = XmlReader.Create(stream, settings))
            {
                while (reader.Read())
                {
                    if (reader.NodeType != XmlNodeType.Element)
                    {
                        continue;
                    }

                    if (reader.Name != "XmlModel")
                    {
                        throw new XmlParseException("Root element must be <XmlModel>.");
                    }

                    var xml = XmlSerializer.Deserialize(reader) as XmlModel;

                    if (xml == null)
                    {
                        throw new XmlParseException("Failed to parse XML.");
                    }

                    return xml;
                }
            }
        }

        private static readonly XmlSerializer XmlSerializer;
    }
}

